/**
 * <sf-bridge-call-kids> — Call kids button (full-width)
 * Spec: docs/specs/cards/bridge.md §sf-bridge-call-kids
 * ADR-B03: full-width imposed by parent via class="full-width"
 */
import { html, LitElement, type TemplateResult } from 'lit';
import { customElement, property, state } from 'lit/decorators.js';
import { msg } from '@lit/localize';
import { sciFiCommonStyles } from '../../../styles/common.js';
import { bridgeStyles } from '../styles.js';
import type { BridgeCallKidsConfig } from '../../../types/config.js';
import { bridgeToast } from '../bridge-toast.js';
import '../../../components/sf-icon/sf-icon.js';

const TAG = 'sf-bridge-call-kids';

@customElement(TAG)
export class SfBridgeCallKids extends LitElement {
  static override styles = [sciFiCommonStyles, bridgeStyles];

  @property({ attribute: false }) config!: BridgeCallKidsConfig;
  @property({ attribute: false }) hass: any;
  @state() private _loading: boolean = false;

  override render(): TemplateResult {
    if (!this.hass || !this.config) return html``;
    const icon = this.config.icon ?? 'mdi:bullhorn';
    const label = this.config.name ?? msg('Call the kids');

    return html`
      <button
        class="call-kids-btn"
        ?disabled="${this._loading}"
        @click="${this._press}"
      >
        <sf-icon
          icon="${this._loading ? 'mdi:loading' : icon}"
          class="${this._loading ? 'spin' : ''}"
          .connection="${this.hass.connection}"
        ></sf-icon>
        ${label}
      </button>
    `;
  }

  private _press(): void {
    const label = this.config.name ?? msg('Call the kids');
    this._loading = true;
    bridgeToast(this, `📣 ${label}`, false);
    void this.hass
      .callService('input_button', 'press', { entity_id: this.config.entity })
      .finally(() => {
        this._loading = false;
      });
  }
}

declare global {
  interface HTMLElementTagNameMap {
    [TAG]: SfBridgeCallKids;
  }
}
